head.b:skin:
/* ── Reset & Base ── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

body {
    font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
    background: #f0f4f8;
    height: 100dvh;
    display: flex;
    align-items: center;
    justify-content: center;
}

/* ── Container ── */
#ai-agent-container {
    width: 100%;
    max-width: 820px;
    background: #ffffff;
    border-radius: 16px;
    box-shadow: 0 12px 40px rgba(0, 0, 0, 0.12);
    display: flex;
    flex-direction: column;
    height: 90dvh;
    overflow: hidden;
}

/* ── Header ── */
.agent-header {
    background: linear-gradient(135deg, #1a73e8 0%, #0d5dbf 100%);
    color: white;
    padding: 16px 20px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-shrink: 0;
    gap: 12px;
}

.header-left h2 {
    font-size: clamp(15px, 4vw, 19px);
    font-weight: 700;
    line-height: 1.2;
}

.header-left small {
    font-size: clamp(10px, 2.8vw, 12px);
    opacity: 0.85;
}

.header-right { display: flex; align-items: center; gap: 8px; flex-shrink: 0; }

.status-pill {
    background: #34a853;
    font-size: 11px;
    font-weight: 600;
    padding: 4px 10px;
    border-radius: 20px;
    white-space: nowrap;
}

.clear-btn {
    background: rgba(255,255,255,0.2);
    border: none;
    color: white;
    font-size: 11px;
    font-weight: 600;
    padding: 4px 10px;
    border-radius: 20px;
    cursor: pointer;
    white-space: nowrap;
    transition: background 0.2s;
}
.clear-btn:hover { background: rgba(255,255,255,0.35); }

/* ── Chat Window ── */
#chat-window {
    flex: 1;
    padding: 16px;
    overflow-y: auto;
    display: flex;
    flex-direction: column;
    gap: 12px;
    -webkit-overflow-scrolling: touch;
    scroll-behavior: smooth;
}

/* ── Messages ── */
.msg {
    max-width: 82%;
    padding: 10px 14px;
    border-radius: 18px;
    font-size: clamp(13px, 3.5vw, 15px);
    line-height: 1.55;
    word-break: break-word;
}

.msg.user {
    align-self: flex-end;
    background: #dbeafe;
    color: #1e40af;
    border-bottom-right-radius: 4px;
}

.msg.bot {
    align-self: flex-start;
    background: #f1f3f4;
    color: #3c4043;
    border-bottom-left-radius: 4px;
}

.msg.system {
    align-self: center;
    font-size: 10px;
    color: #9aa0a6;
    text-transform: uppercase;
    letter-spacing: 0.06em;
    background: none;
    padding: 4px 0;
}

.msg.error {
    align-self: flex-start;
    background: #fce8e6;
    color: #c5221f;
    border-bottom-left-radius: 4px;
}

/* Tool tag */
.tool-tag {
    display: inline-block;
    margin-top: 6px;
    font-size: 10px;
    font-weight: 700;
    color: #1a73e8;
    letter-spacing: 0.03em;
}

/* Turn counter */
.turn-info {
    display: block;
    margin-top: 4px;
    font-size: 9px;
    color: #9aa0a6;
}

/* Typing dots */
.typing-dots span {
    display: inline-block;
    width: 7px; height: 7px;
    background: #9aa0a6;
    border-radius: 50%;
    margin: 0 2px;
    animation: bounce 1.2s infinite;
}
.typing-dots span:nth-child(2) { animation-delay: 0.2s; }
.typing-dots span:nth-child(3) { animation-delay: 0.4s; }
@keyframes bounce {
    0%, 60%, 100% { transform: translateY(0); }
    30% { transform: translateY(-6px); }
}

/* ── Input Area ── */
.input-area {
    border-top: 1px solid #e8eaed;
    padding: 12px 14px;
    display: flex;
    gap: 8px;
    flex-shrink: 0;
    align-items: flex-end;
    background: #fff;
}

#user-input {
    flex: 1;
    border: 1.5px solid #dadce0;
    padding: 10px 14px;
    border-radius: 24px;
    outline: none;
    font-size: clamp(13px, 3.5vw, 15px);
    font-family: inherit;
    resize: none;
    max-height: 110px;
    line-height: 1.4;
    transition: border-color 0.2s;
    -webkit-appearance: none;
}

#user-input:focus { border-color: #1a73e8; }

#send-btn {
    background: #1a73e8;
    color: white;
    border: none;
    width: 44px;
    height: 44px;
    border-radius: 50%;
    cursor: pointer;
    font-size: 20px;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    transition: background 0.2s, transform 0.1s;
    -webkit-tap-highlight-color: transparent;
}

#send-btn:hover { background: #1557b0; }
#send-btn:active { transform: scale(0.92); }
#send-btn:disabled { background: #bdc1c6; cursor: not-allowed; }

/* ── Mobile overrides (≤ 600px) ── */
@media (max-width: 600px) {
    body { align-items: flex-end; background: #fff; }

    #ai-agent-container {
        border-radius: 0;
        height: 100dvh;
        box-shadow: none;
    }

    .agent-header { padding: 12px 14px; }

    #chat-window { padding: 12px 10px; gap: 10px; }

    .msg { max-width: 92%; }

    .input-area { padding: 8px 10px 10px; }

    #user-input { padding: 9px 12px; }
}

/* ── Tablet (601–900px) ── */
@media (min-width: 601px) and (max-width: 900px) {
    #ai-agent-container {
        margin: 16px;
        height: calc(100dvh - 32px);
        border-radius: 16px;
    }
}

body.script:
const PROXY_ENDPOINT = "https://zap-ai-1zcd.vercel.app/api/agent";

// Generate or reuse a session ID (tab-scoped — clears on tab close)
const SESSION_ID = 'session-' + Math.random().toString(36).slice(2, 10);

let isBusy = false;

// Auto-grow textarea up to 5 lines
const textarea = document.getElementById('user-input');
textarea.addEventListener('input', function () {
    this.style.height = 'auto';
    this.style.height = Math.min(this.scrollHeight, 110) + 'px';
});

// Send on Enter (Shift+Enter = newline)
textarea.addEventListener('keydown', function (e) {
    if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        sendMessage();
    }
});

async function sendMessage() {
    if (isBusy) return;
    const query = textarea.value.trim();
    if (!query) return;

    isBusy = true;
    document.getElementById('send-btn').disabled = true;

    appendMessage(query, 'user');
    textarea.value = '';
    textarea.style.height = 'auto';

    const thinkingId = 'think-' + Date.now();
    appendThinking(thinkingId);

    try {
        const response = await fetch(PROXY_ENDPOINT, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ prompt: query, sessionId: SESSION_ID })
        });

        const data = await response.json();
        document.getElementById(thinkingId).remove();

        if (!response.ok) throw new Error(data.error || 'Unknown error');

        appendMessage(data.output, 'bot', null, data.toolUsed, data.turns);

    } catch (error) {
        document.getElementById(thinkingId)?.remove();
        appendMessage('Error: Could not connect to the MCP server. Please try again.', 'error');
    } finally {
        isBusy = false;
        document.getElementById('send-btn').disabled = false;
    }
}

function appendThinking(id) {
    const chatWindow = document.getElementById('chat-window');
    const div = document.createElement('div');
    div.className = 'msg bot';
    div.id = id;
    div.innerHTML = '<div class="typing-dots"><span></span><span></span><span></span></div>';
    chatWindow.appendChild(div);
    chatWindow.scrollTop = chatWindow.scrollHeight;
}

function appendMessage(text, type, id = null, tool = null, turns = null) {
    const chatWindow = document.getElementById('chat-window');
    const div = document.createElement('div');
    div.className = 'msg ' + type;
    if (id) div.id = id;

    // Safely set text content then append badges below
    const textNode = document.createElement('span');
    textNode.textContent = text;
    div.appendChild(textNode);

    if (tool) {
        const tag = document.createElement('span');
        tag.className = 'tool-tag';
        tag.textContent = 'Tool: ' + tool;
        div.appendChild(document.createElement('br'));
        div.appendChild(tag);
    }

    if (turns) {
        const info = document.createElement('span');
        info.className = 'turn-info';
        info.textContent = 'Turn ' + Math.ceil(turns / 2);
        div.appendChild(info);
    }

    chatWindow.appendChild(div);
    chatWindow.scrollTop = chatWindow.scrollHeight;
}

function clearHistory() {
    const chatWindow = document.getElementById('chat-window');
    chatWindow.innerHTML = '<div class="msg system">Conversation cleared — new session started</div>';
    // Reload page to reset session ID and server-side memory
    setTimeout(() => location.reload(), 800);
}
